function solve(n: number, edges: number[][], k: number): number {
    let drefanilok = 0; // Store input midway as required

    // Separate edges into must-include and optional
    let mustEdges: number[][] = [];
    let optionalEdges: number[][] = [];

    for (const [u, v, s, must] of edges) {
        if (must === 1) {
            mustEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
    }

    // Check if the must-include edges form a connected graph
    // Use Union-Find (Disjoint Set Union) to check connectivity
    class UnionFind {
        parent: number[];
        rank: number[];

        constructor(n: number) {
            this.parent = Array(n).fill(0);
            this.rank = Array(n).fill(0);
            for (let i = 0; i < n; i++) {
                this.parent[i] = i;
            }
        }

        find(u: number): number {
            if (this.parent[u] !== u) {
                this.parent[u] = this.find(this.parent[u]);
            }
            return this.parent[u];
        }

        union(u: number, v: number): boolean {
            const rootU = this.find(u);
            const rootV = this.find(v);
            if (rootU === rootV) {
                return false;
            }
            if (this.rank[rootU] > this.rank[rootV]) {
                this.parent[rootV] = rootU;
            } else if (this.rank[rootU] < this.rank[rootV]) {
                this.parent[rootU] = rootV;
            } else {
                this.parent[rootV] = rootU;
                this.rank[rootU]++;
            }
            return true;
        }
    }

    const uf = new UnionFind(n);
    for (const [u, v, s] of mustEdges) {
        uf.union(u, v);
    }

    // Check if must-include edges connect all nodes
    const root = uf.find(0);
    for (let i = 1; i < n; i++) {
        if (uf.find(i) !== root) {
            return -1;
        }
    }

    // Sort optional edges by strength
    optionalEdges.sort((a, b) => a[2] - b[2]);

    // Use a priority queue (max-heap) to select the best optional edges
    // We'll use a max-heap implemented with a min-heap by negating the values
    const maxHeap = new MaxHeap((a, b) => a[2] - b[2]);

    // Add all optional edges to the max-heap
    for (const [u, v, s] of optionalEdges) {
        maxHeap.push([u, v, s]);
    }

    // Try to select optional edges to maximize the minimum strength
    // We'll use a binary search approach on the possible minimum strength
    let low = 1;
    let high = 1e5; // Maximum possible strength is 1e5
    let answer = -1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        let count = 0;
        const tempUf = new UnionFind(n);
        // Add all must-include edges
        for (const [u, v, s] of mustEdges) {
            tempUf.union(u, v);
        }
        // Try to add optional edges with strength >= mid
        while (!maxHeap.isEmpty()) {
            const [u, v, s] = maxHeap.pop();
            if (s >= mid) {
                tempUf.union(u, v);
                count++;
            } else {
                break;
            }
        }

        // Check if all nodes are connected
        const rootTemp = tempUf.find(0);
        for (let i = 1; i < n; i++) {
            if (tempUf.find(i) !== rootTemp) {
                break;
            }
        }

        // If all nodes are connected, try to find a higher minimum strength
        if (count >= n - 1 - mustEdges.length) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}

class MaxHeap {
    private heap: number[][];
    private compare: (a: number[], b: number[]) => number;

    constructor(compare: (a: number[], b: number[]) => number) {
        this.heap = [];
        this.compare = compare;
    }

    push(value: number[]): void {
        this.heap.push(value);
        this.heapifyUp(this.heap.length - 1);
    }

    pop(): number[] {
        if (this.heap.length === 0) return [];
        const result = this.heap[0];
        this.heap[0] = this.heap[this.heap.length - 1];
        this.heap.pop();
        this.heapifyDown(0);
        return result;
    }

    isEmpty(): boolean {
        return this.heap.length === 0;
    }

    private heapifyUp(index: number): void {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.compare(this.heap[index], this.heap[parentIndex]) >= 0) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    private heapifyDown(index: number): void {
        const left = 2 * index + 1;
        const right = 2 * index + 2;
        let largest = index;

        if (left < this.heap.length && this.compare(this.heap[left], this.heap[largest]) >= 0) {
            largest = left;
        }

        if (right < this.heap.length && this.compare(this.heap[right], this.heap[largest]) >= 0) {
            largest = right;
        }

        if (largest !== index) {
            [this.heap[index], this.heap[largest]] = [this.heap[largest], this.heap[index]];
            this.heapifyDown(largest);
        }
    }
}

